function LicenseConfig.initConfig()
    initSeasonConfig(FileUtil.getConfigFromCsv("setting/LicenseSeason.csv", 3))
    initRewardConfig(FileUtil.getConfigFromCsv("setting/LicenseReward.csv", 3))
    initExchangeRewardConfig(FileUtil.getConfigFromCsv("setting/LicenseExchangeReward.csv", 3))
    initRefreshTaskConfig(FileUtil.getConfigFromCsv("setting/LicenseRefreshTask.csv", 3))
    initWeekEXPLimitConfig(FileUtil.getConfigFromCsv("setting/LicenseWeekEXPLimit.csv", 3))
    if isClient then
        initGrandPriceConfig(FileUtil.getConfigFromCsv("setting/LicenseGrandPrice.csv", 3))
        initTabConfig(FileUtil.getConfigFromCsv("setting/LicenseTab.csv"))
    else
        GameLicense:initSeason()
    end
end

function LicenseConfig:getGrandPriceConfigBySeason(season, rewardType)
    local result = {}
    for i, price in pairs(self.PriceConfig) do
        if price.Season == season and price.RewardType == rewardType then
            table.insert(result, price)
        end
    end

    for i, item in pairs(result) do
        result[i].Index = i
    end
    return result
end

