function LicenseConfig:exchangeTime(data)
    local times = DateUtil.date2BeiJingTime({
        year = tonumber(data[1]),
        month = tonumber(data[2]),
        day = tonumber(data[3]),
        hour = tonumber(data[4]) or 0,
        min = tonumber(data[5]) or 0,
        sec = tonumber(data[6]) or 0
    })
    return times
end

function LicenseConfig:calculateSeason()
    local data = {}
    for index, config in pairs(self.SeasonConfig) do
        data[index] = {
            seasonStart = self:exchangeTime(StringUtil.split(config.SeasonStartDate, ",")),
            seasonEnd = self:exchangeTime(StringUtil.split(config.SeasonEndDate, ",")),
            exchangeStart = self:exchangeTime(StringUtil.split(config.ExchangeStartDate, ",")),
            exchangeEnd = self:exchangeTime(StringUtil.split(config.ExchangeEndDate, ","))
        }
    end

    local time = os.time()
    local seasonDate = -1
    local exchangeDate = -1
    local periodDate = -1
    local endSeasonDate = -1
    local lastSeasonStartTime = -1
    for index, date in pairs(data) do
        if time >= date.seasonStart and time < date.seasonEnd then
            seasonDate = index
            endSeasonDate = date.seasonEnd
        end
        if time >= date.exchangeStart and time < date.exchangeEnd then
            exchangeDate = index
        end
        if time >= lastSeasonStartTime and time < date.seasonStart and lastSeasonStartTime ~= date.seasonStart then
            periodDate = index - 1
        end
        lastSeasonStartTime = date.seasonStart
    end

    return seasonDate, exchangeDate, endSeasonDate, periodDate
end

function LicenseConfig:calculateWeek(seasonDate)
    local time = os.time()
    local seasonConfig = self:getSeasonConfigBySeason(seasonDate)
    local seasonTime = self:exchangeTime(StringUtil.split(seasonConfig.SeasonStartDate, ","))
    local firstWeekEnd = DateUtil.getWeekLastTime(seasonTime, true) + 24 * 60 * 60 + 60
    if time < firstWeekEnd then
        return 1
    end
    local week = math.ceil((time - firstWeekEnd) / (7 * 24 * 60 * 60))
    return week + 1  ---加上第一周
end

function LicenseConfig:getSeasonEndTime(season)
    local seasonConfig = self:getSeasonConfigBySeason(season)
    if not seasonConfig then
        return -1
    end
    local seasonEnd = self:exchangeTime(StringUtil.split(seasonConfig.SeasonEndDate, ","))
    return seasonEnd
end

